Object.assign(window.search, {"doc_urls":["introduction.html#简介","thought/summary.html#废话","thought/shoushijingshen.html#收拾精神","thought/yinguo.html#因果","thought/jianchenzhongchen.html#奸臣忠臣","thought/zizhi.html#自知","thought/hongyuwei.html#宏与微","thought/guidingyuxiguan.html#规定与习惯","thought/zhenxiang.html#真相","thought/xinhelv.html#心律","thought/chongsheng.html#重生","thought/huoquxinxidenenglihegenjushishifenxidenenglihezuochuxingweidenengli.html#获取真相的能力和根据事实分析的能力和做出行为的能力","collection/summary.html#收集","collection/wenjiabaoxierenshijianghua.html#温家宝总理卸任时的话","books/summary.html#读书笔记","books/weirenchushi.html#为人处世事而已","books/weirenchushi.html#走多远或许和与谁一起有关","books/weirenchushi.html#提升身价让别人看重你","books/weirenchushi.html#观人对自己也对别人","books/weirenchushi.html#口才也是一种实力说话要花心思花心思其实是对这样说话没形成习惯的人说的","books/weirenchushi.html#底牌不能轻易露示弱不可耻","books/weirenchushi.html#会办事操控力","books/weirenchushi.html#职场为自己而战"],"index":{"documentStore":{"docInfo":{"0":{"body":4,"breadcrumbs":0,"title":0},"1":{"body":0,"breadcrumbs":0,"title":0},"10":{"body":0,"breadcrumbs":0,"title":0},"11":{"body":0,"breadcrumbs":0,"title":0},"12":{"body":0,"breadcrumbs":0,"title":0},"13":{"body":0,"breadcrumbs":0,"title":0},"14":{"body":0,"breadcrumbs":0,"title":0},"15":{"body":0,"breadcrumbs":0,"title":0},"16":{"body":0,"breadcrumbs":0,"title":0},"17":{"body":0,"breadcrumbs":0,"title":0},"18":{"body":0,"breadcrumbs":0,"title":0},"19":{"body":0,"breadcrumbs":0,"title":0},"2":{"body":0,"breadcrumbs":0,"title":0},"20":{"body":0,"breadcrumbs":0,"title":0},"21":{"body":0,"breadcrumbs":0,"title":0},"22":{"body":0,"breadcrumbs":0,"title":0},"3":{"body":0,"breadcrumbs":0,"title":0},"4":{"body":0,"breadcrumbs":0,"title":0},"5":{"body":0,"breadcrumbs":0,"title":0},"6":{"body":0,"breadcrumbs":0,"title":0},"7":{"body":0,"breadcrumbs":0,"title":0},"8":{"body":0,"breadcrumbs":0,"title":0},"9":{"body":0,"breadcrumbs":0,"title":0}},"docs":{"0":{"body":"如果生命就是来这一趟吃吃喝喝，或者嘻嘻哈哈，到死我不知道活着干什么。你可以说你的一生都是为了让你身边的人过得更好，而为了这个，你又不得不让别人过得不好来进行人与人斗达到你的目的的话，我不知道你对全人类又有什么作用？我觉得我们该有思想的觉悟和思考，不让别人愚弄我们，而且我们的存在可以为了全人类的幸福而活着，大概是件有意思的事情。当然这是一家之言，你也有你的想法观念，但是记住了，如果世界上只有一种意识观念，那么一定是错误的，看看道德经里面充满了辩证法，真好，世界本就美好，而不该是一种声音一种颜色一种观念，如果这样，那我们应该多些思考。恒无欲也，以观其眇；恒有欲也，以观其所噭。 人类的共同努力应该解放全人类的双手，让技术等等非人类去为人类做事，而不是让技术把人变得更没有时间，技术是为了解放全人类的双手，而不是一些人拿来压榨和控制另一部分人的工具和手段。 世界上有那么多主义观念，何时才能达到随便你有什么主义观念，都可以在任何时间任何地点随意表达，只要不妨碍别人就行。如果世界上任何一个角落都可以自由表达自己的思想主义想法，那么便是全人类思想解放。 但愿我们都可以拥有自由的思想和思考，为全人类的解放做出自己的贡献。 这本书仅仅是记录自己想要说的话或者自己的思考。希望不会碰到瓷娃娃。希望结交一些爱读书的朋友，一起探讨问题或者某件事情，或者CS本身。 Email: 5u4ccggbr@mozmail.com Blog Messages","breadcrumbs":"简介 » 简介","id":"0","title":"简介"},"1":{"body":"写一些大家都知道的废话。","breadcrumbs":"废话 » 废话","id":"1","title":"废话"},"10":{"body":"死过之后才有重生。要先死才行。所以打破从生下来到现在所有的整个环境灌输给你的思想，然后有选择性的接受保留，或发现新的思想观念等等，也算作一种重生，而这样重生之后的你，该开“天眼”，剥离了政治文化宗教等等，而重新实事求是，用“天眼”（事物的本来去看，规律的本来去看）去看待他们本身，便是重生。","breadcrumbs":"废话 » 重生 » 重生","id":"10","title":"重生"},"11":{"body":"这三个能力伴随了一生的主要时间。这一生都在追求认识事物和事实（比如：社会运行规律，银行运行规律和本质，经济金融等等发展规律，政治规律和人的本性，计算机运行原理，物理原理，化学原理，数学，哲学，法律，计算机系统，软件开发等等）的能力，同时做出合理合适的行为。如果事实都看不到看不懂看不清，那么后面都建立在虚假虚伪之上一定是错误的方向。所以实事求是，增强自己认识实事的能力就要不断增强自己综合整体素质和知识储备。 获取真相的能力（是什么）：这里真相需要自己有能力去获取，而不是被任何组织和个人带入他们的利益立场之中。如果我们首先打碎了我们之前所认为的一切认知，然后从其中根据实事求是的选择哪些是真相的或许会清晰很多。这里面当然会受自己的整体素质和知识储备还有自己所坚持坚信的立场所影响（我们用真善美的立场去看事情本身）。 根据事实分析的能力（为什么）：这里就是用因果去看为什么会产生这个结果？这里面依旧对自己有很强大的整体素质和知识储备的要求。 做出合理合适行为的能力（怎么办）：根据事实和自己整体素质和知识储备还有自己的目的立场，做出让事情朝着自己目的立场的方向发展，这里就是我们对事物的主观能动性的具体实践和体现。","breadcrumbs":"废话 » 获取真相的能力和根据事实分析的能力和做出行为的能力 » 获取真相的能力和根据事实分析的能力和做出行为的能力","id":"11","title":"获取真相的能力和根据事实分析的能力和做出行为的能力"},"12":{"body":"尘埃落定的真相或真实发生的事情。","breadcrumbs":"收集 » 收集","id":"12","title":"收集"},"13":{"body":"改革已到了攻坚阶段 现在，改革到了攻坚阶段。没有政治体制改革的成功，经济体制改革不可能进行到底，已经取得的成果，还有可能得而复失，社会上新产生的问题也不能从根本上得到解决。文化大革命，这样历史的悲剧，还有可能重新发生。每个有责任的党员和领导干部都应该感到紧迫感。","breadcrumbs":"收集 » 温家宝总理卸任时的话 » 温家宝总理卸任时的话","id":"13","title":"温家宝总理卸任时的话"},"14":{"body":"读的课外书籍的一些记录，之后查看可以唤醒自己阅读时的记忆而已。","breadcrumbs":"读书笔记 » 读书笔记","id":"14","title":"读书笔记"},"15":{"body":"","breadcrumbs":"读书笔记 » 处事书籍 » 为人处世/事而已","id":"15","title":"为人处世/事而已"},"16":{"body":"主动有意识地选择和结交，建立自己的信誉，人际关系网络 对方的态度是自己的镜子 拔掉人脉中的杂草 有自己的原则, 个人口碑/形象树立 朋友是资源，可以相互使用但不能透支，不到万不得已不要用。 与强者结盟但不仗势欺人。可能是一条快速改变现状的路径。可为强者提供服务，联合一起做事。（其本质还是借助强者的名气技术,也可保护自己等等实现自己目标）。同时观察学习。 善于用人（自己再强大也只是一人之力）。（刘邦）。（知人善任）。 与人为善，而后选择性结交。 平时多联系，即使是简单的问候。不可急功近利（这是意识上的问题，交朋友是可交而交，不是有用而交） 路径窄处，留一步与人行；滋味浓时，减三分让人食。当然原则问题不可让步。","breadcrumbs":"读书笔记 » 处事书籍 » 走多远或许和与谁一起有关","id":"16","title":"走多远或许和与谁一起有关"},"17":{"body":"适时包装自己，把握机会推销自己。 树立自己的形象（个人品性，名气，技术实力，业务能力，为人等等）（诚实守信，认真对待身边每个人，顾全大局全局利益出发成事） 要互利（单方面索取不可长久），必要时被人利用也是聪明的做法（其为互利而已）。自己对别人有价值才会被人利用才会得到与人互利的机会（我/他有何用）。 适当隐藏，学会装神秘（才能得到别人尊重，不应该让别人看到你的底细；让别人知道你，但不要让别人了解你。没人知道底细，就没人感到失望。隐藏好自己，不要一开始就展示你的全部，要胸有城府）。从容闲适。传言不置可否，神秘感（或者虚张声势让人看不透），其实就是制造自我的矛盾感让别人猜不到，适可而止。制造神秘感，让人充满好奇。制造悬念，不要过早全盘托出。 没有伯乐，就要造势。（营销就是这个道理）（适度的自抬身价,使得其他人肯定你的价值）（人都愿意相信价格昂贵的商品，且重视）（造出来的名气，但实力可以）。（各种手段创造条件造势）（将自己最最优秀的一面表现出来） 学会适应，融入大环境。（没什么话语权，只能按照大环境的规则和潜规则办事） 设法赢得大家重视：适时“消失”，制造突然的“地球离开我就不转”的效果，提升自己在团队中的重要性，让别人重视自己。（当然你要负责一些重要的业务，且有实力等等，才有这效果）。习惯了某种东西，便不会在意，失去后才知重要。 充满魅力的人格。（凝聚众人，得到大量追随者） 发展自己长处和优势，创造自己成功的事业。","breadcrumbs":"读书笔记 » 处事书籍 » 提升身价，让别人看重你","id":"17","title":"提升身价，让别人看重你"},"18":{"body":"眼睛 穿着 化妆 提包 抽烟 口头禅 字体 言行举止 发型 等等。。。 内心或与外在相反，内心或与外在相同，取决于性格。 通过种种识别人心(识别出对方底牌，隐藏好自己底牌)，看到听到有时都只是假象和骗局。","breadcrumbs":"读书笔记 » 处事书籍 » 观人(对自己也对别人)","id":"18","title":"观人(对自己也对别人)"},"19":{"body":"赞美（渴望得到赞扬是人性中最根深蒂固的本性，人类很渴望被肯定，赞美是最直接的肯定）（肯定对方的成绩优点努力等）（有实际支撑的赞美不是,注意观察）（赞美一个人引以为荣的事情）（捧场最快速拉近彼此距离） 在人背后赞美（借他人之口赞赏别人）（会让别人更加感受到真诚） 委婉表达，不可直说。（让人思之得意,让人听明白）（先夸后委婉说出做这件事的不可能的条件，间接拒绝） 不能和盘托出（不要让公域的人进入自己的私域，是对自己的保护）（只有百分之一的人能够严守秘密）（知人知面不知心，或许会被人玩弄股掌之中）（脆弱面被别人掌握将来会成为你的软肋） 模糊表态拥有弹性，话说出去不能反悔。说话不可太绝，要留有余地。自信的人懂得谦卑，不说满话，进可攻退可守。 ​","breadcrumbs":"读书笔记 » 处事书籍 » 口才也是一种实力，说话要花心思（花心思其实是对这样说话没形成习惯的人说的）","id":"19","title":"口才也是一种实力，说话要花心思（花心思其实是对这样说话没形成习惯的人说的）"},"2":{"body":"无论贩夫走卒，还是引车卖浆者流；都要做收拾精神，自作主张的大英雄。 不要过度过分在意那些大众的声音，你是你自己你有你的思考和思想，不因为某个人愤怒而轻易否定自己的决定和原则，而如果对方确实有其道理，则权衡做出自己的决定。而如果思维境界，或者从观念之始就是不和调和的，这世界不是只有一个样子，求同存异是种智慧。 很有意思的一件事情，就像正反，好坏，善恶，天地，死活，美丑，白黑，长短，明暗，实虚，有无，难易，高下，前后等等这些，谁都能看得出来每个词语均是使用对立面组成。 那么到底什么是纯粹的好和坏呢？我们被教育的是好人坏人，那么评判好人坏人就要有些标准，符合大众道德标准的便是好人，不符合的便是坏人，世界真的就是这么简单么？或者媒体宣传的哪个是好人哪个是坏人，那么就一定是这样么?我们大众或者说众生太容易被媒体带着跑了，似乎我们是一个没有思想的机器一样，媒体给予什么信息那么我们就去信什么信息，首先第一点：媒体放出来的信息想要达到什么目的呢？第二点：这些媒体所报道的事情真真正正是事物本来面目么？第三点：媒体信息来源是否真实呢？（*这一点我们假定真实）。第四点：会不会有谁在操纵媒体宣传呢？而我们就是被欺骗的一份子呢？我只是想说当我们看到信息的时候一定需要自己思考或者多方面信息搜集然后根据人性（而不是反人性）去看待。所以被大众或者媒体报道的坏人和好人，我们也需要有自己论证或者思考的过程。活到现在我们看到媒体两面性的报道也太多了吧。 总之，能够用怀疑的眼光看待世界和社会是每个人都应该具备的基本素质，而至于自己思考的结果则根据个人整体素质因人而异，但是怀疑否定的意识应该伴随一生。被愚弄可能也是好事，但明智明事实之后还甘愿被愚弄可能也是件好事。 希望我们都能够拥有自己的思考和具备睿智思考的素质。为国家大好河山和人类的幸福时刻准备着。 天下皆知美为美，恶已。皆知善，斯不善矣。有无之相生也，难易之相成也，长短之相刑也，高下之相盈也，意声之相和也，先后之相隋恒也。是以圣人居无为之事，行不言之教；万物昔而弗始，为而弗志也，成功而弗居也。夫唯居，是以弗去。","breadcrumbs":"废话 » 收拾精神 » 收拾精神","id":"2","title":"收拾精神"},"20":{"body":"潜龙在渊。(该说和不该说的搞清楚，不要让形势对自己不利)(少亮底牌是对自己最好的保护) 深藏不露，守拙待时。(该展露锋芒便展露不该便手拙保护自己)(你要比别人聪明但不要让别人知道) 适时示弱不可耻。恰当的表现优秀。太露锋芒将被人嫉妒暗害，要么比别人强很多(让别人一辈子也赶不上)，要么不要露锋芒。 人更关注自己，而别人的灾难比别人的成功更能让人快乐。 少说饶舌话，多做事。 一忍可以支百勇。(多些理智少些鲁莽) 祸从口出。(说话要经过思考)(装糊涂未必不好，把别人弄的云里雾里别人便不再问了)(真相不一定每个人都想知道，真相是残酷的对自己的反噬不容小觑) 把握万分之一的机会。(机会很小也要认真对待，其实全力以赴该会成功) 吃亏是福。(吃小亏，是种助人，助人便有助人的用)(凡事吃点小亏多谦让别人一些)(对立面相互转化)","breadcrumbs":"读书笔记 » 处事书籍 » 底牌不能轻易露，示弱不可耻","id":"20","title":"底牌不能轻易露，示弱不可耻"},"21":{"body":"软磨硬泡(托人办事，不因为别人拒绝为难而放弃，积极采取行动) 坐收渔翁之利(不要让自己成为收利人的工具，也可以制造收利的条件) 抓住问题要害。做事轻重缓急。则效率提高。 不过于自信，不轻看他人。 不盲目行动，明确目标，制造达到目标的条件。(没有目标会迷茫不成事) 变相“要挟”也可行。(求人办事被拒绝后，可以为对方做出某种假设，合乎情理，让对方改变。没人喜欢威胁，掂量好威胁成功的可能性) 求人办事不要操之过急。 做任何事情都要掌握好火候。(做这件事情的时机很重要)(轻重缓急，大小主次) 先走为上。(不如别人时，避开是非，另辟蹊径)(夫唯居，是以弗去)","breadcrumbs":"读书笔记 » 处事书籍 » 会办事(操控力)","id":"21","title":"会办事(操控力)"},"22":{"body":"“好人”要少当(当你为一些人做事时可能会为自己树敌，思考清楚。不要为了好人缘或者所有人喜欢你，而做一些看上去对同事有利其实让自己招恨的事情) 不要无端被欺(上司要维护好关系，但是也要争取自己利益，这样才能得到尊重和应有的待遇，否则谁都会欺负你)(猜透上司的心思，用各种手段对付) 一味的屈从会成为软柿子，谁都可以利用你。一方面尽力最好交代的任务，一方面要据理力争自己的利益。 学会套近乎 别总是自己出手(借刀杀人，充分利用各种矛盾，找到可以为自己所用的刀，然后再打击对方) 机会不能等（没有尝试过怎么知道自己不喜欢不擅长？不能等别人为你铺好路,而应该自己去走路，失败然后走出自己的路）（不要去等而是行动）（抓住时机，敢于冒险）（机会是争取来的不是等来的） 随机进退勿勇闯（该进则进该退则退）（以退为进） 小心老板的底线（了解老板的偏好和底线,不要触碰,或找合适的机会触碰）（公共场合与老板站在一起，对的支持宣扬，错的打圆场） 关键时刻敢拍板 问清楚，多做些（做事之前各方面问题问好考虑清楚，做事之时相关事情都做好，不要机械化说什么就做什么挤牙膏一样） 一味沉默只能表示无能没有主见（忠言可以顺耳只是进言方式问题调整下） 坐热冷板凳（默默增强自己实力，谦卑搞好人际关系，学会忍耐和克制）（磨练而已）","breadcrumbs":"读书笔记 » 处事书籍 » 职场为自己而战","id":"22","title":"职场为自己而战"},"3":{"body":"道生一，一生二，二生三，三生万物。 这世间因果律不虚，而道德经中阐述虽充满辩证，但其中依旧离不开因果作用。前人或以天命传奇蛊惑人心，如刘邦白帝子。或幽王失道失德，申起而身灭。当人们心中认定何为君主何为领导，顺人心而为，以其因，必得其果。毁其因，其果必亡。 反道而行，必霍乱自身。社会，政治，人类等等无一可反道。所以七年十年三十年可见答案。 现代化也好，传统文化也好，都会有其结果。明主自会权衡自会繁荣本国，欲速不达。 凡事观其始因，推其果。毁便毁其因，盛则做其因。 确定结果，控制条件。","breadcrumbs":"废话 » 因果 » 因果","id":"3","title":"因果"},"4":{"body":"说奸臣和忠臣都只是自己处于目前教育和信息来源中的一点点体会而已，然后有一点想说的。 有这么一个角度去看: 奸臣为了自己私欲而且看不到自己做的事情的严重后果（只说这种情况的奸臣），忠臣意识为道德国之大局可舍自己（只说这种情况的忠臣)。若如此，现在太多人只是为了钱，整个国家也就陷入了危机。应该有道德观念，有自己优秀的文化，而这些文化意识形态是为了让整个国家更好，而不是一时的眼前利益。","breadcrumbs":"废话 » 奸臣忠臣 » 奸臣忠臣","id":"4","title":"奸臣忠臣"},"5":{"body":"如果就大的范围而言，比如整个社会，世界，自然，宇宙等等。想要自知难如登天(因为这些领域太过宏大，一辈子不一定能掌握全部)。想要知道了解自己只能在某个范围之内(而且是自己能了如指掌的领域范围)，比如在自己的公司，在家庭里面，或者在自己研究的领域里，可以做到自知。(那么众生或者在某个领域的门外汉和入门者，被骗的几率很高，也就是说别人想怎么说就怎么说，你又没有个思考和认证，那么骗子对你来说就是真理) 我在学习我的专业之时，自己知道自己以目标为导向后知道自己缺什么然后找到合适的资源去掌握去达到目的。这该是自知的。如果其中参杂了别的比如面子或者炫耀或者其他等等虚无缥缈对专业技术实力提升没有任何意义的虚伪，那么这个自知和之后行为的便会变得扭曲，在寻找学习资料时候的也会不符合实际情况造成时间的浪费，而时间就是生命。 对某个领域了解越深入，则越知道自己在其中处于什么位置，能更好的在其中有所成就。就达到目的而言的自知，那就缺什么，需要什么就去学什么，太快是浪费时间太慢也是浪费时间，每日有所得到有所进步且距离目的越来越近便是好的，自知之后设定略高的目标是个不错的选择。 抓住问题本质，实事求是寻找自己需要的资源去学习。一个个问题去解决,并快速掌握让自己对国家个别人解决多部分人解决不了的问题。","breadcrumbs":"废话 » 自知 » 自知","id":"5","title":"自知"},"6":{"body":"就微观细节组成或影响宏观而言，可以向把握简单易懂的宏观，把握之后遇到某部分则可以再去细致入微的研究，应该更有意思，此时应该是即知全貌又知细节，算是有意思的把握事物全貌，而不是木讷呆板且枯燥的进行，这样忘得也快。 如学习Rust可先快速阅读文档并且快速编写小项目，大体掌握，而后每个概念再细致研究。","breadcrumbs":"废话 » 宏与微 » 宏与微","id":"6","title":"宏与微"},"7":{"body":"只是想说规定去做事情然后形成习惯之后，那种一开始的艰难和效率底下会有好转尤其是心理的压力的感觉会没有；那么一开始的按照规定去做事会觉得很累，这种很累的感觉是对未知的恐惧感等等内耗自己和事情本身对身心的使用两者加和还有两者相互作用产生的大于两者的反应。如果出去自己的内耗，而就事情本身来说，在一开始就信心慢慢且乐于做，那么没有累的感觉不是没有可能。 而当越来越熟悉身心都形成习惯/记忆，这事情便会很轻松。在相同的时间里重复做这件事情，如果事情也没有效率提升，那么就个人而言没有任何进步的话是不是属于对时间/生命的浪费呢？但是会有人为你支付这段时间的钱财。 总的来说，做任何事情，在任何阶段，除去自我做事的心理上的内耗，会轻松很多，因为本来就没有困难的事情，任何事情细分之后跟你走路一样简单。 但是要做个懒人，因为只有懒人才会有更强大的内心去驱动做事效率的提升，而不是造成大批量人类时间的浪费。","breadcrumbs":"废话 » 规定与习惯 » 规定与习惯","id":"7","title":"规定与习惯"},"8":{"body":"对立面相互转化。真相就是假相，假相就是真相。当所有人都认为假相为真相时那便是真相，古代皇权那是真相么？却说给个忠。相信的人多了，便是真相，不同的声音出来，哪怕是长远来看是对这个群体更有利的也会被把假相当真相的一群人给灭掉。那真相还重要么？当然重要，实事求是一直都是推动事物往前发展的最根本最正确的方法。所以求个真，没人求真了，也就没啥进步可言了，人被机器愚弄，人非人，人无自由了，没思考了，没求真了，还不如机器。小到几个人，大到全世界。 任何的主义和别人口里的真相或许都是某个层次的有道理。又或许根本就没有真相，都是条件的自然结果，想要某种结果就去创造某结果的条件，世间根本就没有真相这个概念，或许“真相”这词只是对立面的人造出的批判现在的工具而已。所以你愿相信便是“真相”，谁能让你相信谁就是真理。 于是骗子，传销，洗脑便有了可能。 每个人都是在自己的相信里过活。真相这概念就是用来骗人的，用来让形势有利于自己的一种手段。都只是因果。 所以佛家不让我们入相。凡所有相，皆是虚妄，若见相非相，即见如来。现在又加深了理解，相不一定非要是实体，原来意识层面也皆为相。所有皆相。","breadcrumbs":"废话 » 真相 » 真相","id":"8","title":"真相"},"9":{"body":"修行以行制性，悟道以性施行；觉者由心生律，修者以律制心。 成事者必有成事的条件，外部称其为机遇的难以预测外（当然这机遇又和内在品性又关系）；一定会存在内在成事品性，当并无此品性如何得其？上面一段话或许有解决办法：以行制性，而后以性施行，再到由心生律。 那么一切又皆可以培养起来，以行制性，后以性施行。","breadcrumbs":"废话 » 心*律 » 心*律","id":"9","title":"心*律"}},"length":23,"save":true},"fields":["title","body","breadcrumbs"],"index":{"body":{"root":{"5":{"df":0,"docs":{},"u":{"4":{"c":{"c":{"df":0,"docs":{},"g":{"df":0,"docs":{},"g":{"b":{"df":0,"docs":{},"r":{"@":{"df":0,"docs":{},"m":{"df":0,"docs":{},"o":{"df":0,"docs":{},"z":{"df":0,"docs":{},"m":{"a":{"df":0,"docs":{},"i":{"df":0,"docs":{},"l":{".":{"c":{"df":0,"docs":{},"o":{"df":0,"docs":{},"m":{"df":1,"docs":{"0":{"tf":1.0}}}}},"df":0,"docs":{}},"df":0,"docs":{}}}},"df":0,"docs":{}}}}}},"df":0,"docs":{}}},"df":0,"docs":{}}}},"df":0,"docs":{}},"df":0,"docs":{}},"df":0,"docs":{}}},"b":{"df":0,"docs":{},"l":{"df":0,"docs":{},"o":{"df":0,"docs":{},"g":{"df":1,"docs":{"0":{"tf":1.0}}}}}},"df":0,"docs":{},"e":{"df":0,"docs":{},"m":{"a":{"df":0,"docs":{},"i":{"df":0,"docs":{},"l":{"df":1,"docs":{"0":{"tf":1.0}}}}},"df":0,"docs":{}}},"m":{"df":0,"docs":{},"e":{"df":0,"docs":{},"s":{"df":0,"docs":{},"s":{"a":{"df":0,"docs":{},"g":{"df":1,"docs":{"0":{"tf":1.0}}}},"df":0,"docs":{}}}}}}},"breadcrumbs":{"root":{"5":{"df":0,"docs":{},"u":{"4":{"c":{"c":{"df":0,"docs":{},"g":{"df":0,"docs":{},"g":{"b":{"df":0,"docs":{},"r":{"@":{"df":0,"docs":{},"m":{"df":0,"docs":{},"o":{"df":0,"docs":{},"z":{"df":0,"docs":{},"m":{"a":{"df":0,"docs":{},"i":{"df":0,"docs":{},"l":{".":{"c":{"df":0,"docs":{},"o":{"df":0,"docs":{},"m":{"df":1,"docs":{"0":{"tf":1.0}}}}},"df":0,"docs":{}},"df":0,"docs":{}}}},"df":0,"docs":{}}}}}},"df":0,"docs":{}}},"df":0,"docs":{}}}},"df":0,"docs":{}},"df":0,"docs":{}},"df":0,"docs":{}}},"b":{"df":0,"docs":{},"l":{"df":0,"docs":{},"o":{"df":0,"docs":{},"g":{"df":1,"docs":{"0":{"tf":1.0}}}}}},"df":0,"docs":{},"e":{"df":0,"docs":{},"m":{"a":{"df":0,"docs":{},"i":{"df":0,"docs":{},"l":{"df":1,"docs":{"0":{"tf":1.0}}}}},"df":0,"docs":{}}},"m":{"df":0,"docs":{},"e":{"df":0,"docs":{},"s":{"df":0,"docs":{},"s":{"a":{"df":0,"docs":{},"g":{"df":1,"docs":{"0":{"tf":1.0}}}},"df":0,"docs":{}}}}}}},"title":{"root":{"df":0,"docs":{}}}},"lang":"English","pipeline":["trimmer","stopWordFilter","stemmer"],"ref":"id","version":"0.9.5"},"results_options":{"limit_results":30,"teaser_word_count":30},"search_options":{"bool":"AND","expand":true,"fields":{"body":{"boost":1},"breadcrumbs":{"boost":1},"title":{"boost":2}}}});